import sys
from typing import List
import math

class Solution:
    def longestNiceSubarray(self, arr: List[int]) -> int:
        max_len = 0
        left = 0
        prime_factors = {}
        for right in range(len(arr)):
            self.update_prime_factors(arr[right], prime_factors)
            while not self.is_perfect_square(prime_factors):
                self.update_prime_factors(arr[left], prime_factors, -1)
                left += 1
            max_len = max(max_len, right - left + 1)
        return max_len

    def update_prime_factors(self, num, prime_factors, val=1):
        i = 2
        while i * i <= num:
            while num % i == 0:
                prime_factors[i] = prime_factors.get(i, 0) + val
                num //= i
            i += 1
        if num > 1:
            prime_factors[num] = prime_factors.get(num, 0) + val

    def is_perfect_square(self, prime_factors):
        for count in prime_factors.values():
            if count % 2 != 0:
                return False
        return True

