#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int longestNiceSubarray(vector<int>& arr) {
        int max_len = 0;
        int left = 0;
        unordered_map<int, int> prime_factors;
        for (int right = 0; right < arr.size(); right++) {
            update_prime_factors(arr[right], prime_factors);
            while (!is_perfect_square(prime_factors)) {
                update_prime_factors(arr[left], prime_factors, -1);
                left++;
            }
            max_len = max(max_len, right - left + 1);
        }
        return max_len;
    }

private:
    void update_prime_factors(int num, unordered_map<int, int>& prime_factors, int val = 1) {
        for (int i = 2; i * i <= num; i++) {
            while (num % i == 0) {
                prime_factors[i] += val;
                num /= i;
            }
        }
        if (num > 1) {
            prime_factors[num] += val;
        }
    }

    bool is_perfect_square(const unordered_map<int, int>& prime_factors) {
        for (const auto& pair : prime_factors) {
            if (pair.second % 2 != 0) {
                return false;
            }
        }
        return true;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> arr(n);
    for (int i = 0; i < n; i++) cin >> arr[i];
    Solution sol;
    int ans = sol.longestNiceSubarray(arr);
    cout << ans << '\n';
    return 0;
}
